Diagnose the primary performance bottleneck in this CUDA kernel
running on an NVIDIA A10G GPU (ridge point: 62 FLOP/byte).
```cuda
#include <cuda_runtime.h>
#include <cstdio>

constexpr int BLOCK_SIZE = 128;
constexpr int STATE0 = 192;
constexpr int STATE1 = 160;
constexpr int TAPS = 128;

__global__ __launch_bounds__(BLOCK_SIZE, 1) void spill_reference(const float* x, const float* coeff, float* out, int n) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= n) {
        return;
    }

    int mask = n - 1;
    float state0[STATE0];
    float state1[STATE1];
    float taps[TAPS];
    float mix[64];

    #pragma unroll
    for (int i = 0; i < TAPS; ++i) {
        taps[i] = coeff[(blockIdx.x * 31 + i) & mask] * (0.5f + 0.001953125f * static_cast<float>(i));
    }

    #pragma unroll
    for (int i = 0; i < STATE0; ++i) {
        float xv = x[(tid + i) & mask];
        float yv = coeff[(tid + i * 7) & mask];
        state0[i] = __fadd_rn(__fmul_rn(xv, 0.75f + 0.0009765625f * static_cast<float>(i & 31)), __fmul_rn(yv, 0.25f));
    }

    #pragma unroll
    for (int i = 0; i < STATE1; ++i) {
        float xv = x[(tid + i * 3 + 11) & mask];
        float yv = coeff[(tid + i * 5 + 19) & mask];
        state1[i] = __fadd_rn(__fmul_rn(xv, 0.625f + 0.00048828125f * static_cast<float>(i & 63)), __fmul_rn(yv, 0.375f));
    }

    #pragma unroll
    for (int i = 0; i < 64; ++i) {
        mix[i] = __fadd_rn(state0[(i * 3) % STATE0], state1[(i * 5) % STATE1]);
    }

    float acc = 0.0f;
    #pragma unroll
    for (int phase = 0; phase < 9; ++phase) {
        #pragma unroll
        for (int tap = 0; tap < TAPS; ++tap) {
            float s0 = state0[(phase * 19 + tap) % STATE0];
            float s1 = state1[(phase * 23 + tap + 37) % STATE1];
            float m0 = mix[(tap + phase * 7) & 63];
            float c0 = taps[tap];
            float c1 = taps[(tap + phase * 11 + 7) & (TAPS - 1)];
            acc = __fadd_rn(acc, __fmul_rn(s0, c0));
            acc = __fadd_rn(acc, __fmul_rn(s1, c1));
            acc = __fadd_rn(acc, __fmul_rn(m0, 0.015625f));
        }
    }

    out[tid] = acc;
}

int main() {
    const int n = 1 << 20;
    const size_t bytes = static_cast<size_t>(n) * sizeof(float);
    float* h = new float[n];
    float *x, *coeff, *out;
    cudaMalloc(&x, bytes);
    cudaMalloc(&coeff, bytes);
    cudaMalloc(&out, bytes);
    for (int i = 0; i < n; ++i) {
        h[i] = static_cast<float>((i * 13) % 257) * 0.0078125f;
    }
    cudaMemcpy(x, h, bytes, cudaMemcpyHostToDevice);
    cudaMemcpy(coeff, h, bytes, cudaMemcpyHostToDevice);
    spill_reference<<<(n + BLOCK_SIZE - 1) / BLOCK_SIZE, BLOCK_SIZE>>>(x, coeff, out, n);
    cudaMemcpy(h, out, bytes, cudaMemcpyDeviceToHost);
    std::printf("%f\n", h[9]);
    cudaFree(x);
    cudaFree(coeff);
    cudaFree(out);
    delete[] h;
    return 0;
}

